const all = $input.all();
const doctors = all.filter(i => i.json.hasOwnProperty('Specialty')).map(i => i.json);
const appointments = all.filter(i => !i.json.hasOwnProperty('Specialty')).map(i => i.json);

const weekdayOf = d => d.toLocaleDateString('en-US', { weekday: 'long', timeZone: 'UTC' });
const iso = d => d.toISOString().slice(0, 10);
const today = new Date();
const days14 = [];
for (let i = 0; i < 14; i++) {
  const d = new Date(Date.UTC(today.getUTCFullYear(), today.getUTCMonth(), today.getUTCDate() + i));
  days14.push({ date: iso(d), weekday: weekdayOf(d) });
}
const calendar = days14.map(d => `${d.date} = ${d.weekday}${d.date === days14[0].date ? ' (TODAY)' : ''}`).join('\n');

const roster = doctors.map(doc => {
  const avail = (doc.Available_Days || '').toString().split(',').map(s => s.trim()).filter(Boolean);
  const maxPerDay = doc.max_patients_per_day || 20;
  const hours = doc.Available_Time || 'N/A';
  const avg = doc.Avg_Time || 15;
  const bookable = days14.filter(day => avail.includes(day.weekday)).map(day => {
    const count = appointments.filter(a => a.Doctor_Name === doc.Doctor_Name && a.Date === day.date && a.Status !== 'Completed' && a.Status !== 'Cancelled').length;
    const left = maxPerDay - count;
    return `${day.date}${left <= 0 ? ' (FULL)' : ` (${left} slot${left === 1 ? '' : 's'} left)`}`;
  }).join(', ') || 'none in next 14 days';
  return `- ${doc.Doctor_Name} (${doc.Specialty || 'General'}): days ${avail.join('/') || 'N/A'}, hours ${hours}, avg consult ${avg} mins, max patients per day ${maxPerDay}\n  Bookable dates (next 14 days): ${bookable}`;
}).join('\n');

return [{ json: { roster, calendar, today: days14[0].date, todayWeekday: days14[0].weekday, total_doctors: doctors.length } }];

const currentQueue = $('Increment Queue Number').first().json.Current_Queue_Number;
const avgTime = $input.first().json.Avg_Time || 15;
const patientsFor30Min = Math.ceil(30 / avgTime);
const patientsFor60Min = Math.ceil(60 / avgTime);
return [{ json: {
  token0: currentQueue,
  token30: currentQueue + patientsFor30Min,
  token60: currentQueue + patientsFor60Min,
  currentDoctor: $('Nurse Queue Webhook').first().json.body.doctorName
}}];
